import { i as verifyPassword } from "./content-XYN0YFXN.js";
//#region src/lib/auth.ts
var AUTH_KEY = "terionix_admin";
function isAuthenticated() {
	if (typeof window === "undefined") return false;
	return localStorage.getItem(AUTH_KEY) === "true";
}
async function login(password) {
	console.log("[auth] login called, password length:", password.length);
	try {
		const result = await verifyPassword({ data: { password } });
		console.log("[auth] verifyPassword result:", result);
		if (result) {
			localStorage.setItem(AUTH_KEY, "true");
			console.log("[auth] login success");
			return true;
		}
		console.log("[auth] password mismatch");
	} catch (e) {
		console.error("[auth] login error:", e);
		return false;
	}
	return false;
}
async function logout() {
	localStorage.removeItem(AUTH_KEY);
	try {
		await fetch("http://localhost:8001/api/auth/logout", {
			method: "POST",
			credentials: "include"
		});
	} catch {}
}
//#endregion
export { login as n, logout as r, isAuthenticated as t };
